#include<bits/stdc++.h>
using namespace std;
long long n,m;
long long c[51];
bool check(long long x)
{
    long long sum=0;
    for(long long i=1;i<=n;i++)
    {
        if(c[i]>=x)
        {
            continue;
        }
        sum+=x-c[i];
        if(sum>m||sum>x)
        {
            return false;
        }
    }
    return true;
}
int main()
{
    scanf("%lld%lld",&n,&m);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&c[i]);
    }
    long long l=0,r=1e9,best;
    while(l<=r)
    {
        long long mid=(l+r)/2;
        if(check(mid))
        {
            best=mid;
            l=mid+1;
        }
        else
        {
            r=mid-1;
        }
    }
    printf("%lld",best);
    return 0;
}
